input.command:
RESV="compute-a7-9 compute-a7-27 compute-a7-46 compute-a7-54 compute-a8-20 compute-a8-41 compute-a8-52 compute-b5-32 compute-b5-43 compute-b6-3 compute-b6-13 compute-b6-21 compute-b6-33 compute-b7-6 compute-b7-19 compute-b6-50 compute-b6-53 compute-b6-54 compute-b6-56 compute-b7-41 compute-b7-42"
idle=$(sinfo -p standard -t idle -h -o "%n" 2>/dev/null)
# leaf membership function via topology.conf
declare -A bucket
for n in $idle; do
  echo "$RESV" | grep -qw "$n" && continue
  leaf=$(awk -v node="$n" '
    /^SwitchName=.*Nodes=/ && !/Switches=/ {
      sw=$1; sub(/SwitchName=/,"",sw);
      nl=$2; sub(/Nodes=/,"",nl);
      cmd="scontrol show hostnames "nl" 2>/dev/null";
      while((cmd|getline h)>0){ if(h==node){print sw; exit} } close(cmd)
    }' /etc/slurm/topology.conf)
  bucket[$leaf]="${bucket[$leaf]} $n"
done
for k in "${!bucket[@]}"; do cnt=$(echo ${bucket[$k]}|wc -w); echo "LEAF $k : $cnt idle ->${bucket[$k]}"; done | sort -t: -k2 -rn

